var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"후우...... 후우......","JPN":"ふう……、ふう……","ENG":"Whew... Ha...","TWN":"呼……呼……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"땀을 많이 흘리시네요.","JPN":"汗だくですね。","ENG":"You're sweating up a storm.","TWN":"妳流了好多汗呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물수건이라도 가져다 드릴까요?","JPN":"おしぼりでも持ってきましょうか？","ENG":"Can I get you a towel or something?","TWN":"要幫妳拿條濕毛巾之類的嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......필요 없어.","JPN":"……いらない。","ENG":"...No.","TWN":"……不用。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 자꾸 친한 척하지 말아 줬으면 좋겠는데.","JPN":"馴れ馴れしくしないでほしいんだけど。","ENG":"And can you stop acting so chummy?","TWN":"只要你別老過來跟我裝熟就行了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......좀 달라붙지도 말고.","JPN":"……あと、ちょっと離れてよね。","ENG":"...And give me some personal space.","TWN":"……也別靠得這麼近。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하하. 부끄러움이 많은 성격인가 보네요.","JPN":"ハハハ、シャイな性格なんですかね？","ENG":"Hahaha. You're the shy type, aren't you?","TWN":"哈哈哈，這麼清純啊。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 너무 뻔뻔하다는 생각은 해 본 적 없어?","JPN":"あんたが厚かましすぎるんだよ。","ENG":"Has it ever occurred to you that you're just shameless?","TWN":"你不覺得自己很不要臉嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가요?","JPN":"僕がですか？","ENG":"Me?","TWN":"我？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 좀 내성적인 편이라고 생각하는데요. 하하.","JPN":"僕は内気なほうだと思いますが……ハハハ。","ENG":"I always thought of myself as an introvert. Haha.","TWN":"我還覺得自己有些內向呢，哈哈。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 그래. 그러시겠지.","JPN":"あっそう、そうだろうね。","ENG":"Sure. Whatever.","TWN":"喔，是嗎？我想也是。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"데뷔전치고는 멀쩡해 보이는군, 신입.","JPN":"デビュー戦にしては何ともなさそうだな、新人。","ENG":"Not bad for your first battle, rookie.","TWN":"以初陣來說表現得還不錯，新人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다친 곳은 없나?","JPN":"ケガはないか？","ENG":"Are you hurt anywhere?","TWN":"沒受傷吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......보다시피.","JPN":"……見てのとおり。","ENG":"Not a scratch on me.","TWN":"……如妳所見。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생각보다 좀 시시했어.","JPN":"思ったより、つまらなかった。","ENG":"Actually, that was kinda lame.","TWN":"比我想像得還要無聊。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"제법이군.","JPN":"やるな。","ENG":"I'm impressed.","TWN":"做得不錯。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 허세는 부리지 않는 게 좋아. ","JPN":"だが、あまり調子に乗らないほうが良いぞ？ ","ENG":"But bragging won't get you very far. ","TWN":"但最好不要逞強。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"겁이 없는 건 좋지만, 무모하게 날뛰다가 소리소문 없이 사라지는 애송이들은 질리도록 봐 왔거든.","JPN":"物怖じしないのは良いことだが、無謀に暴れては消えていく若造を山ほど見てきた。","ENG":"I like that you're fearless, but I've seen too many reckless amateurs run to their own demise.","TWN":"不害怕戰鬥很好，但我已經看膩了那些因莽撞而死去的小鬼了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아! 미나 양, 저는 자신감 넘치는 모습도 마음에 든다고 생각합니다.","JPN":"あ、ミナさん！僕はそんな自信満々なところも気に入りましたよ。","ENG":"Oh! As for me, I found your overwhelming confidence most charming, Mina!","TWN":"啊！米娜小姐，妳那自信滿滿的樣子我也很喜歡喔。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기분 나빠.","JPN":"気持ち悪い。","ENG":"Creep.","TWN":"噁心。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"더러워.","JPN":"気持ち悪い。","ENG":"Couldn't agree more.","TWN":"有夠下流。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든 작전은 완료한 것 같군. 돌아가도록 하지.","JPN":"とりあえず作戦完了のようだな。戻るとしよう。","ENG":"In any case, I think our job here is done. Let's head back.","TWN":"總之，作戰好像已經結束了，我們回去吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오랜만이군요, 스승님.","JPN":"師匠、お久しぶりです。","ENG":"Long time no see, Master!","TWN":"好久不見，師父。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"원대복귀를 환영합니다.","JPN":"ご復帰、おめでとうございます。","ENG":"Welcome back.","TWN":"歡迎回來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이게 몇 년 만이죠?","JPN":"何年ぶりでしょうね。","ENG":"How long has it been?","TWN":"已經過了多少年了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"글쎄. 날짜 헤아리는 취미는 없어서.","JPN":"さあ、日にちを数える趣味はないからな。","ENG":"Not sure. I haven't exactly been counting the days.","TWN":"誰知道，我可沒有計算年月的嗜好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그나저나, 못 본 사이에 너도 많이 늙었네.","JPN":"それはさておき、見ないうちにお前もずいぶん老けたな。","ENG":"Anyway, you've certainly aged over the years.","TWN":"不過在這段日子裡，妳也變老了很多呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......귀여운 얼굴로 끔찍한 소리를 잘도 하시네요.","JPN":"……そんな可愛い顔して、相変わらずの毒舌ですね。","ENG":"Ouch... I see you haven't changed a bit.","TWN":"……您可真是會用那張可愛的臉說出過分的話呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 요괴 할망구 같으니.","JPN":"この妖怪ババァが。","ENG":"Easy for you to say, you creepy vampire.","TWN":"明明自己才是個妖怪老太婆。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐. 계속 궁금했던 건데 왜 다들 저 꼬맹이를 스승님이라고 부르는 거지?","JPN":"あのさ、ずっと気になってたんだけど、なんであの子のことを師匠と呼ぶの？","ENG":"Hey. So why does everyone keep calling that kid \\"Master\\"?","TWN":"喂，我從之前就想問了，為什麼所有人都叫這個矮子師父啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"겉보기엔 딸이라고 해도 믿을 것 같은데.","JPN":"見た目的には、娘だと言われても信じちゃいそうだけど。","ENG":"She could practically pass for that lady's daughter!","TWN":"看她的樣子，說是妳的女兒都會有人信吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 그건 말이죠. 저 꼬맹이가 생긴 거랑 다르게 나이가 아주 많거든요.","JPN":"あ、それはですね。あのおチビちゃんは見かけによらず高齢なんですよ。","ENG":"Well, you see... She's actually much older than she looks.","TWN":"啊，妳說這個呀。因為那個矮子的實際年齡，可比看上去要大得多喔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 저 성격 나쁜 꼬맹이가 정말 저 아줌마의 스승이란 거야?","JPN":"じゃあ、あの性格悪いチビっ子が、本当にあのオバサンの師匠なわけ？","ENG":"So that mean little kid really is that old lady's Master?","TWN":"你說這個性格糟糕的矮子，真的是那個大嬸的師父？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누가 아줌마라는 거죠?","JPN":"誰がオバサンですって？","ENG":"Who are you calling an \\"old lady\\"?","TWN":"妳說誰是大嬸啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"누가 성격 나쁜 꼬맹이냐?! ","JPN":"誰が性格悪いチビっ子だ！？ ","ENG":"Who are you calling a \\"mean-little kid\\"?! ","TWN":"誰是性格糟糕的矮子啊？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 버르장머리 없는 애송이들이.","JPN":"この生意気な小娘が。","ENG":"Why you little punks...","TWN":"真是個沒禮貌的小孩。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하여간 요즘 젊은 것들은 예의라는 걸 모르는......!!","JPN":"まったく、最近の若者は礼儀ってものを知らんのか……！！","ENG":"You young folks don't have any manners these days!","TWN":"最近的年輕人都不懂什麼叫禮貌！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......스승님의 세대관엔 찬성하지 않지만, 우리 신입사원에겐 교육이 좀 필요할 것 같군요.","JPN":"……師匠の世代観には同意できませんが、新人にはちょっとしたお仕置きが必要かもしれませんね。","ENG":"...I'd hate to sound like an old fart like our Master here, but I do agree we might teach the rookie a lesson.","TWN":"……雖然我不贊同師父的世代觀，但確實有必要教育一下這位新人呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"예를 들어 감봉이라든가.","JPN":"たとえば、減俸とか……？","ENG":"Like docking her pay, for instance.","TWN":"比如說減薪啊什麼的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"히익!","JPN":"ひいっ！","ENG":"What?!","TWN":"咿！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 오늘은 바쁜 날이니 교육은 잠시 연기하도록 하겠습니다.","JPN":"ですが、今日は色々バタバタしているので、お仕置きはまた今度にしましょうか。","ENG":"But I'm very busy today, so we'll defer that lesson for another time.","TWN":"不過今天太忙了，教育新人的事就暫且放一邊吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우선 제 소개부터 하죠.","JPN":"まずは、私の自己紹介をしましょう。","ENG":"Let me introduce myself.","TWN":"那我就先來自我介紹一下吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저는 이곳 코핀 컴퍼니의 대표이사직을 맡고 있는 이수연이라고 합니다.","JPN":"私はここ、コフィンカンパニーの代表取締役をつとめるカナミ・キズナです。","ENG":"My name is Lee Sooyeon, the President of the Coffin Company.","TWN":"我是科芬公司的董事長李秀妍。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희 코핀 컴퍼니는 관리국에서 인증 받은 대 침식전 전문 기업.","JPN":"我がコフィンカンパニーは、管理局の認定を受けた侵食戦専門の企業。","ENG":"The Coffin Company is an Administration-certified company for combating interdimensional corruption.","TWN":"我們科芬公司是經管理局認證，專門對抗侵蝕體的企業。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"통칭, 태스크포스 컴퍼니입니다.","JPN":"通称、タスクフォースカンパニーです。","ENG":"We're also known as a TASKFORCE Company.","TWN":"統稱“特遣勢力公司”。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"보다시피 규모가 그리 큰 편은 아닙니다만.......","JPN":"ご覧のとおり、そこまで規模が大きくはありませんが……","ENG":"We're not that big as you can see...","TWN":"如妳所見，本公司的規模並不是很大。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국에서 정식으로 넘버링 라이선스를 받은 몇 안 되는 민간 기업이기도 하죠.","JPN":"管理局からナンバリングライセンスの正式認定を受けた数少ない民間企業の一つです。","ENG":"But we're still one of the few private companies licensed by the Administration.","TWN":"但本公司是擁有管理局正式編號證書，為數不多的民營企業之一。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"해적이나 다름없는 잡다한 미인증 회사들과는 격이 다르다는 자부심을 가져도 좋습니다.","JPN":"盗賊同然の未認定会社とは格が違いますので、そこは自負心を持ってもよいでしょう。","ENG":"We're totally different from those uncertified companies, who are no more than a bunch of lousy pirates.","TWN":"妳可以自豪地說，我們和那些像海盜一樣、亂七八糟的未認證公司格調是不同的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리 회사에 입사한 걸 환영합니다. 유미나 양.","JPN":"ご入社おめでとうございます。ヤナギ・ミナさん。","ENG":"So welcome to the company, Mina.","TWN":"歡迎加入本公司，劉米娜小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아...... 생각보다 높으신 분이었네......","JPN":"思ったよりもお偉いさんだったんだね……","ENG":"Oh... I didn't know you were such a big shot...","TWN":"啊……看來這個人的地位比我想得還要高呢……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 잘 부탁해.","JPN":"これからよろしく。","ENG":"Thanks, lady.","TWN":"那就多指教啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......말이 좀 짧군요. ","JPN":"……いきなりタメ語ですか。 ","ENG":"Not much into social etiquette, are you. ","TWN":"……米娜小姐說話還挺隨性的呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"역시 펜릴 소대에 어울리는 훌륭한 인성입니다.","JPN":"さすがフェンリル小隊にピッタリな、立派なお人柄だこと。","ENG":"I can see why you're perfect for the Fenrir Squad.","TWN":"果然是非常適合芬里爾小隊的個性。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마음 같아서는 본사의 유서 깊은 예의범절을 철저하게 가르쳐 주고 싶지만......","JPN":"……当社の由緒ある礼儀作法を叩き込みたいところですが……","ENG":"If I could, I would teach you all there is to company etiquette but...","TWN":"雖然我很想把本公司歷史悠久的傳統禮儀徹底地教給妳。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아까도 말했듯이 시간이 촉박하군요.","JPN":"さっきも言ったとおり、時間がありません。","ENG":"As I mentioned, I just don't have time.","TWN":"但就像我剛才說的，時間緊迫。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"펜릴 소대가 처리해야 할 새로운 임무가 있습니다.","JPN":"フェンリル小隊担当の新しい任務があります。","ENG":"We have a new mission for Fenrir Squad.","TWN":"芬里爾小隊有新的任務。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"또 임무가 있다고?","JPN":"また任務だと？","ENG":"Another mission?","TWN":"又有任務了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하룻밤에 연속작전이라니, 흔한 일은 아니군.","JPN":"一夜で連続作戦を行うなんて、めずらしいな。","ENG":"One after another? This is unusual.","TWN":"一個晚上竟然有連續兩個作戰，這還真是少見呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여기에 태스크포스가 우리만 있는 것도 아닐 텐데?","JPN":"ここにいるタスクフォースカンパニーは、私たちだけではないはずだが？","ENG":"We can't be the only TASKFORCE here, right?","TWN":"這裡又不是只有我們這支特遣小隊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니면 관리국과 계약한 업체들이 단체로 파업이라도 했나?","JPN":"それとも、管理局と契約した業者が、こぞってストでも起こしてるのか？","ENG":"Or did all the contractors go on strike against the Administration?","TWN":"難道和管理局簽約的公司全都集體罷工了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마요.","JPN":"まさか。","ENG":"Of course not.","TWN":"怎麼可能。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이번 작전은 관리국과 무관한 저희 회사의 프라이빗 오퍼레이션입니다.","JPN":"今回の作戦は管理局とは無関係の、当社独自の作戦です。","ENG":"This mission is our company's private operation. It has nothing to do with the Administration.","TWN":"這次作戰與管理局無關，是本公司的內部任務。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"프라이빗 오퍼레이션?","JPN":"独自作戦だと？","ENG":"Private operation?","TWN":"內部任務？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"はい。","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘, 매우 중요한 용건으로 본사를 방문할 예정이셨던 요인 한 분이 계십니다.","JPN":"本日、極めて重要な案件でご来社される予定だった要人が一人いらっしゃいます。","ENG":"There's someone who was supposed to visit headquarters today on some very important business.","TWN":"今天本來有位要員會來總部，商討一件非常重要的事情。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 본사로 오던 도중, 갑작스런 침식재난으로 인해 현재 침식지역에 고립되신 상태입니다.","JPN":"しかし、当社に向かう途中、突然の侵食に遭遇したため、現在侵食地域に孤立しています。","ENG":"But on the way, they were caught in the corruption disaster and are now isolated in the corruption zone.","TWN":"但他在途中遇到了突如其來的侵蝕災難，現在正被困在侵蝕區域中。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"여러분의 임무는 신속히 해당 요인을 구출하여 본사로 안전하게 모시고 오는 것입니다.","JPN":"皆さんの任務は、その要人をすみやかに救出し、無事に当社までお連れすることです。","ENG":"Your mission is to rescue the asset and safely escort them to headquarters.","TWN":"各位的任務就是迅速地救出該要員，並將他安全地護送至總部。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"요인 구출? 그런 건 특수전 담당일 텐데?","JPN":"要人救出？それは特殊戦担当なのでは？","ENG":"An extraction? That sounds more like a task for the folks over at special ops.","TWN":"救出要員？這不是特戰組的工作嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여긴 나랑 얼간이 제자 놈.","JPN":"こっちは私とマヌケな弟子、","ENG":"In case you forgot... It's just me and this idiot...","TWN":"這裡只有我和笨蛋徒弟……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 오늘 처음 들어와서 앞뒤 구분도 못하는 애송이뿐이라고.","JPN":"あと、入社したてほやほやの小娘だけだ。","ENG":"And a brand new recruit who has no idea what's going on.","TWN":"還有一個剛來什麼都不懂的小鬼。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"구출 작전 같은 섬세한 임무를 맡을 조합이 아냐.","JPN":"救出作戦のような複雑な任務が務まるようなメンバーではない。","ENG":"We're not exactly capable of a complex operation like an extraction.","TWN":"這可不是個能夠接下救出要員這種精細任務的組合。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 그 말씀도 맞습니다만.","JPN":"もちろん、それも一理あります。","ENG":"You make a fair point...","TWN":"確實如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이쪽도 이쪽 나름대로의 고충이 있어서 말이죠.","JPN":"こちらとしても苦渋の選択でした。","ENG":"But we have our own set of problems and we have no choice.","TWN":"但是我們也有我們的苦衷。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"현재 본사에서 동원할 수 있는 카운터 소대는 펜릴 소대가 유일합니다.","JPN":"いま当社で動員できるカウンター小隊はフェンリル小隊だけなので。","ENG":"The only Counter squad that headquarters can mobilize right now is Fenrir Squad.","TWN":"現在總部可以出動的制裁者小隊，就只有芬里爾了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 다시 한 번 강조드립니다만.......","JPN":"あと、改めて念押ししておきますが……","ENG":"And I cannot stress this enough...","TWN":"不過得再強調一次。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 작전은 본사의 존망이 달린 중요 사안입니다.","JPN":"この作戦は、当社の存亡がかかった重要な案件です。","ENG":"This is a very important mission. It could determine the very fate of the company.","TWN":"這次的作戰非常重要，攸關整個公司的存亡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"해당 요인은 반드시 안전하게 구출되어야 합니다.","JPN":"あの方は必ず無事に救出されなければなりません。","ENG":"It's paramount that the asset is brought to safety.","TWN":"請務必安全地救出該要員。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"현재 작전부에서 고립된 요인의 정확한 위치를 파악 중입니다. ","JPN":"現在、孤立した要人の居場所を作戦部で調べています。 ","ENG":"The Operation Department is currently trying to pinpoint the location of the asset. ","TWN":"目前作戰部正在調查受困要員的具體位置。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"펜릴 소대는 즉시 해당 지역으로 출격하여 요인의 안전을 확보하기 바랍니다.","JPN":"フェンリル小隊は、ただちにそのエリアへ出撃、要人の安全を確保してください。","ENG":"In the meantime, please head out to the area with the squad and prepare to secure the asset.","TWN":"希望芬里爾小隊立刻出擊到該區域救出要員，並將他安全護送至總部。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};